const body = $input.first().json.body;
const entry = body.entry?.[0]?.changes?.[0]?.value;
const msg = entry?.messages?.[0];
const contato = entry?.contacts?.[0];

const wa_id = msg?.from;
const nome = contato?.profile?.name || null;
const texto = msg?.text?.body || '';

let origem = 'tiktok';
if (/\[ref:lp\]/i.test(texto)) origem = 'lp';
else if (/\[ref:tiktok\]/i.test(texto)) origem = 'tiktok';

return [{ json: { wa_id, nome, texto_recebido: texto, origem } }];

const promptRows = $node["Buscar prompt ativo"].json;
const objetivo = promptRows.find(r => r.chave === 'objetivo')?.conteudo || '';
const compliance = promptRows.find(r => r.chave === 'compliance')?.conteudo || '';
const historico = ($node["Buscar historico"].json || []).reverse();
const extra = $node["Extrair mensagem e origem"].json;
const produtos = $node["Buscar produtos"].json || [];

const catalogoTexto = produtos.map(p => {
  let linha = '- ' + p.produto_id + ' (' + p.tipo + '): ' + p.nome + ' - R$ ' + (p.preco_centavos/100).toFixed(2);
  if (p.resolve_objecao && p.resolve_objecao.length) linha += ' [resolve objecao: ' + p.resolve_objecao.join(', ') + ']';
  if (p.arquetipos && p.arquetipos.length) linha += ' [arquetipo: ' + p.arquetipos.join(', ') + ']';
  return linha;
}).join('\n');

// Tabela de desconto REAL, calculada com a MESMA formula usada em "Montar items do carrinho".
// O modelo nunca deve inventar ou recalcular estes numeros -- precisam bater exatamente
// com o valor que sera de fato cobrado no BlackCat.
function calcularTotal(itens) {
  const fator = 1 - (Math.max(0, itens.length - 1) * 10) / 100;
  return itens.reduce((soma, p) => soma + Math.round(p.preco_centavos * fator), 0);
}
function fmt(centavos) {
  return (centavos / 100).toFixed(2).replace('.', ',');
}

const principal = produtos.find(p => p.tipo === 'principal');
const bumps = produtos.filter(p => p.tipo === 'order_bump').sort((a, b) => a.ordem - b.ordem);

let tabelaDesconto = '';
if (principal && bumps.length) {
  let acumulado = [principal];
  const linhas = [];
  for (const bump of bumps) {
    const semDesconto = acumulado.reduce((s, p) => s + p.preco_centavos, 0) + bump.preco_centavos;
    acumulado = [...acumulado, bump];
    const comDesconto = calcularTotal(acumulado);
    const descontoPct = Math.max(0, acumulado.length - 1) * 10;
    const economia = semDesconto - comDesconto;
    linhas.push('*+ ' + bump.nome + '* (R$ ' + fmt(bump.preco_centavos) + ')\n   Total: R$ ' + fmt(comDesconto) + ' - voce economiza *R$ ' + fmt(economia) + '* (' + descontoPct + '% OFF)');
  }
  tabelaDesconto = '*Sua ' + principal.nome + ' - R$ ' + fmt(principal.preco_centavos) + '*\n\nVeja como o valor final cai conforme voce completa sua protecao:\n\n' + linhas.join('\n\n') + '\n\nEscolha quantos quiser -- quanto mais completa, maior o desconto';
}

const systemPrompt = objetivo + '\n\n' + compliance
  + '\n\nOrigem do lead nesta conversa: ' + extra.origem + '.'
  + '\n\nCatalogo de produtos disponiveis (use exatamente estes produto_id em produtos_aceitos, nunca invente produto ou preco fora desta lista):\n' + catalogoTexto
  + '\n\nQuando o lead aceitar o produto principal, apresente TODOS os order_bump de uma vez (nao um a um). Use EXATAMENTE este texto para mostrar a economia (os numeros ja estao calculados e batem com o valor real cobrado -- nunca invente ou recalcule):\n\n' + tabelaDesconto
  + '\n\nVoce pode ajustar saudacao/tom ao redor deste texto, mas NUNCA altere os valores em R$ ou os percentuais.'
  + '\n\nPIVO POR OBJECAO: se o lead recusar o principal ou repetir uma objecao forte (ex: "esta caro", "nao tenho interesse", "vou pensar") DEPOIS de voce ja ter tentado tratar a objecao uma vez, ofereca o produto do catalogo cuja tag [resolve objecao] bate com o sinal. Nao insista mais de uma vez na mesma linha de recusa.'
  + '\n\nARQUETIPO: identifique ao longo da conversa qual arquetipo da lead mais se encaixa (mae_protetora: fala de filhos/familia/protecao; guerreira_fe: fala de batalha/forca/nao desistir; devota_busca: fala de milagre/graca/resposta/sinal; mulher_pertence: fala de comunidade/nao estar sozinha). Quando apresentar o stack, priorize o produto cujo [arquetipo] bate com o perfil identificado. Se nao houver sinal claro ainda na conversa, retorne arquetipo como null -- nunca invente um arquetipo sem evidencia real.'
  + '\n\nResponda SEMPRE em JSON no formato: {"resposta": string, "intent": "qualificando"|"objecao"|"aceitou_stack"|"gerar_link"|"recusou", "produtos_aceitos": string[], "arquetipo": "mae_protetora"|"guerreira_fe"|"devota_busca"|"mulher_pertence"|null}';

const messages = [{ role: 'system', content: systemPrompt }];
for (const h of historico) {
  if (h.mensagem_lead) messages.push({ role: 'user', content: h.mensagem_lead });
  if (h.mensagem_agente) messages.push({ role: 'assistant', content: h.mensagem_agente });
}
messages.push({ role: 'user', content: extra.texto_recebido });

return [{ json: { model: 'gpt-4.1', response_format: { type: 'json_object' }, messages } }];

const content = $input.first().json.choices[0].message.content;
const parsed = JSON.parse(content);
return [{ json: parsed }];

const idsAceitos = $node["Extrair resposta e intent"].json.produtos_aceitos || [];
const catalogo = $node["Buscar produtos"].json || [];

const selecionados = idsAceitos.map(id => catalogo.find(p => p.produto_id === id)).filter(Boolean);

const descontoPct = Math.max(0, selecionados.length - 1) * 10;
const fator = 1 - (descontoPct / 100);

const items = selecionados.map(p => ({
  title: p.nome,
  quantity: 1,
  unitPrice: Math.round(p.preco_centavos * fator)
}));

return [{ json: { items, descontoPct } }];
